pub fn load(head: Head, bytes: &[u8]) -> Result<Ping, Error> {
    debug_assert_eq!(head.kind(), crate::frame::Kind::Ping);

    // PING frames are not associated with any individual stream. If a PING
    // frame is received with a stream identifier field value other than
    // 0x0, the recipient MUST respond with a connection error
    // (Section 5.4.1) of type PROTOCOL_ERROR.
    if !head.stream_id().is_zero() {
        return Err(Error::InvalidStreamId);
    }

    // In addition to the frame header, PING frames MUST contain 8 octets of opaque
    // data in the payload.
    if bytes.len() != 8 {
        return Err(Error::BadFrameSize);
    }

    let mut payload = [0; 8];
    payload.copy_from_slice(bytes);

    // The PING frame defines the following flags:
    //
    // ACK (0x1): When set, bit 0 indicates that this PING frame is a PING
    //    response. An endpoint MUST set this flag in PING responses. An
    //    endpoint MUST NOT respond to PING frames containing this flag.
    let ack = head.flag() & ACK_FLAG != 0;

    Ok(Ping { ack, payload })
}

fn grow(&mut self, new_raw_cap: usize) {
    // This path can never be reached when handling the first allocation in
    // the map.

    debug_assert!(self.assert_valid_state("top"));

    // find first ideally placed element -- start of cluster
    let mut first_ideal = 0;

    for (i, pos) in self.indices.iter().enumerate() {
        if let Some(pos) = *pos {
            if 0 == probe_distance(self.mask, pos.hash, i) {
                first_ideal = i;
                break;
            }
        }
    }

    // visit the entries in an order where we can simply reinsert them
    // into self.indices without any bucket stealing.
    let old_indices = mem::replace(&mut self.indices, vec![None; new_raw_cap]);
    self.mask = new_raw_cap.wrapping_sub(1);

    for &pos in &old_indices[first_ideal..] {
        self.reinsert_entry_in_order(pos);
    }

    for &pos in &old_indices[..first_ideal] {
        self.reinsert_entry_in_order(pos);
    }

    debug_assert!(self.assert_valid_state("bottom"));
}

pub fn transition_after(&mut self, mut stream: store::Ptr, is_reset_counted: bool) {
    tracing::trace!(
        "transition_after; stream={:?}; state={:?}; is_closed={:?}; \
         pending_send_empty={:?}; buffered_send_data={}; \
         num_recv={}; num_send={}",
        stream.id,
        stream.state,
        stream.is_closed(),
        stream.pending_send.is_empty(),
        stream.buffered_send_data,
        self.num_recv_streams,
        self.num_send_streams
    );

    if stream.is_closed() {
        if !stream.is_pending_reset_expiration() {
            stream.unlink();
            if is_reset_counted {
                self.dec_num_reset_streams();
            }
        }

        if !stream.state.is_scheduled_reset() && stream.is_counted {
            tracing::trace!("dec_num_streams; stream={:?}", stream.id);
            // Decrement the number of active streams.
            self.dec_num_streams(&mut stream);
        }
    }

    // Release the stream if it requires releasing
    if stream.is_released() {
        stream.remove();
    }
}

pub fn flush(&mut self, cx: &mut Context) -> Poll<io::Result<()>> {
    let span = tracing::trace_span!("FramedWrite::flush");
    let _e = span.enter();

    loop {
        while !self.encoder.is_empty() {
            match self.encoder.next {
                Some(Next::Data(ref mut frame)) => {
                    tracing::trace!(queued_data_frame = true);
                    let mut buf = (&mut self.encoder.buf).chain(frame.payload_mut());
                    ready!(poll_write_buf(Pin::new(&mut self.inner), cx, &mut buf))?
                }
                _ => {
                    tracing::trace!(queued_data_frame = false);
                    ready!(poll_write_buf(
                        Pin::new(&mut self.inner),
                        cx,
                        &mut self.encoder.buf
                    ))?
                }
            };
        }

        match self.encoder.unset_frame() {
            ControlFlow::Continue => (),
            ControlFlow::Break => break,
        }
    }

    tracing::trace!("flushing buffer");
    // Flush the upstream
    ready!(Pin::new(&mut self.inner).poll_flush(cx))?;

    Poll::Ready(Ok(()))
}

pub fn from_parts(src: Parts) -> Result<Uri, InvalidUriParts> {
    if src.scheme.is_some() {
        if src.authority.is_none() {
            return Err(ErrorKind::AuthorityMissing.into());
        }

        if src.path_and_query.is_none() {
            return Err(ErrorKind::PathAndQueryMissing.into());
        }
    } else if src.authority.is_some() && src.path_and_query.is_some() {
        return Err(ErrorKind::SchemeMissing.into());
    }

    let scheme = match src.scheme {
        Some(scheme) => scheme,
        None => Scheme {
            inner: Scheme2::None,
        },
    };

    let authority = match src.authority {
        Some(authority) => authority,
        None => Authority::empty(),
    };

    let path_and_query = match src.path_and_query {
        Some(path_and_query) => path_and_query,
        None => PathAndQuery::empty(),
    };

    Ok(Uri {
        scheme,
        authority,
        path_and_query,
    })
}

fn new_builder(config: &Config) -> Builder {
    let mut builder = Builder::default();
    builder
        .initial_max_send_streams(config.initial_max_send_streams)
        .initial_window_size(config.initial_stream_window_size)
        .initial_connection_window_size(config.initial_conn_window_size)
        .max_header_list_size(config.max_header_list_size)
        .max_send_buffer_size(config.max_send_buffer_size)
        .max_local_error_reset_streams(config.max_local_error_reset_streams)
        .enable_push(false);
    if let Some(max) = config.max_frame_size {
        builder.max_frame_size(max);
    }
    if let Some(max) = config.max_concurrent_reset_streams {
        builder.max_concurrent_reset_streams(max);
    }
    if let Some(max) = config.max_pending_accept_reset_streams {
        builder.max_pending_accept_reset_streams(max);
    }
    if let Some(size) = config.header_table_size {
        builder.header_table_size(size);
    }
    if let Some(max) = config.max_concurrent_streams {
        builder.max_concurrent_streams(max);
    }
    if let Some(dur) = config.reset_stream_duration {
        builder.reset_stream_duration(dur);
    }
    builder
}

fn poll_next(&self) -> Option<Box<hyper_task>> {
    // Drain the queue first.
    self.drain_queue();

    let waker = futures_util::task::waker_ref(&self.is_woken);
    let mut cx = Context::from_waker(&waker);

    loop {
        {
            // Scope the lock on the driver to ensure it is dropped before
            // calling drain_queue below.
            let mut driver = self.driver.lock().panic_if_poisoned();
            match Pin::new(&mut *driver).poll_next(&mut cx) {
                Poll::Ready(val) => return val,
                Poll::Pending => {}
            };
        }

        // poll_next returned Pending.
        // Check if any of the pending tasks tried to spawn
        // some new tasks. If so, drain into the driver and loop.
        if self.drain_queue() {
            continue;
        }

        // If the driver called `wake` while we were polling,
        // we should poll again immediately!
        if self.is_woken.0.swap(false, Ordering::SeqCst) {
            continue;
        }

        return None;
    }
}

pub(super) fn buffer<BB: Buf + Into<B>>(&mut self, mut buf: BB) {
    debug_assert!(buf.has_remaining());
    match self.strategy {
        WriteStrategy::Flatten => {
            let head = self.headers_mut();

            head.maybe_unshift(buf.remaining());
            trace!(
                self.len = head.remaining(),
                buf.len = buf.remaining(),
                "buffer.flatten"
            );
            //perf: This is a little faster than <Vec as BufMut>>::put,
            //but accomplishes the same result.
            loop {
                let adv = {
                    let slice = buf.chunk();
                    if slice.is_empty() {
                        return;
                    }
                    head.bytes.extend_from_slice(slice);
                    slice.len()
                };
                buf.advance(adv);
            }
        }
        WriteStrategy::Queue => {
            trace!(
                self.len = self.remaining(),
                buf.len = buf.remaining(),
                "buffer.queue"
            );
            self.queue.push(buf.into());
        }
    }
}

fn encode_with(&self, buf: &mut Vec<u8>, _context: ()) -> Result<(), crate::Error> {
    buf.reserve(120);

    buf.put_length_prefixed(|buf| {
        // The protocol version number. The most significant 16 bits are the
        // major version number (3 for the protocol described here). The least
        // significant 16 bits are the minor version number (0
        // for the protocol described here)
        buf.extend(&196_608_i32.to_be_bytes());

        if let Some(username) = self.username {
            // The database user name to connect as.
            encode_startup_param(buf, "user", username);
        }

        if let Some(database) = self.database {
            // The database to connect to. Defaults to the user name.
            encode_startup_param(buf, "database", database);
        }

        for (name, value) in self.params {
            encode_startup_param(buf, name, value);
        }

        // A zero byte is required as a terminator
        // after the last name/value pair.
        buf.push(0);

        Ok(())
    })
}

pub async fn create(
    &self,
    email: &str,
    password: String,
) -> Result<AccountId, CreateAccountError> {
    // Hash password whether the account exists or not to make it harder
    // to tell the difference in the timing.
    let hash = self.hash_password(password).await?;

    // Thanks to `sqlx.toml`, `account_id` maps to `AccountId`
    sqlx::query_scalar!(
        // language=PostgreSQL
        "insert into account(email, password_hash) \
         values ($1, $2) \
         returning account_id",
        email,
        // However, since arguments don't link back to the target column,
        // SQLx doesn't know that `PasswordHash` would be a valid argument here.
        hash.to_string(),
    )
    .fetch_one(&self.pool)
    .await
    .map_err(|e| {
        if e.as_database_error().and_then(|dbe| dbe.constraint())
            == Some("account_account_id_key")
        {
            CreateAccountError::EmailInUse
        } else {
            GeneralError::from(e).into()
        }
    })
}

fn fetch_optional<'e, 'q, E>(self, mut query: E) -> BoxFuture<'e, Result<Option<PgRow>, Error>>
    where
        'c: 'e,
        E: Execute<'q, Self::Database>,
        'q: 'e,
        E: 'q,
    {
        // False positive: https://github.com/rust-lang/rust-clippy/issues/12560
        #[allow(clippy::map_clone)]
        let metadata = query.statement().map(|s| Arc::clone(&s.metadata));
        let arguments = query.take_arguments().map_err(Error::Encode);
        let persistent = query.persistent();

        Box::pin(async move {
            let sql = query.sql();
            let arguments = arguments?;
            let mut s = pin!(self.run(sql, arguments, persistent, metadata).await?);

            // With deferred constraints we need to check all responses as we
            // could get a OK response (with uncommitted data), only to get an
            // error response after (when the deferred constraint is actually
            // checked).
            let mut ret = None;
            while let Some(result) = s.try_next().await? {
                match result {
                    Either::Right(r) if ret.is_none() => ret = Some(r),
                    _ => {}
                }
            }
            Ok(ret)
        })
    }

async fn request_upgrade(
    socket: &mut impl Socket,
    _options: &PgConnectOptions,
) -> Result<bool, Error> {
    // https://www.postgresql.org/docs/current/protocol-flow.html#id-1.10.5.7.11

    // To initiate an SSL-encrypted connection, the frontend initially sends an
    // SSLRequest message rather than a StartupMessage

    socket.write(SslRequest::BYTES).await?;

    // The server then responds with a single byte containing S or N, indicating that
    // it is willing or unwilling to perform SSL, respectively.

    let mut response = [0u8];

    socket.read(&mut &mut response[..]).await?;

    match response[0] {
        b'S' => {
            // The server is ready and willing to accept an SSL connection
            Ok(true)
        }

        b'N' => {
            // The server is _unwilling_ to perform SSL
            Ok(false)
        }

        other => Err(err_protocol!(
            "unexpected response from SSLRequest: 0x{:02x}",
            other
        )),
    }
}

fn recv_next_result_column(def: &ColumnDefinition, ordinal: usize) -> Result<MySqlColumn, Error> {
    // if the alias is empty, use the alias
    // only then use the name
    let column_name = def.name()?;

    let name = match (def.name()?, def.alias()?) {
        (_, alias) if !alias.is_empty() => UStr::new(alias),
        (name, _) => UStr::new(name),
    };

    let table = def.table()?;

    let origin = if table.is_empty() {
        ColumnOrigin::Expression
    } else {
        let schema = def.schema()?;

        ColumnOrigin::Table(TableColumn {
            table: if !schema.is_empty() {
                format!("{schema}.{table}").into()
            } else {
                table.into()
            },
            name: column_name.into(),
        })
    };

    let type_info = MySqlTypeInfo::from_column(def);

    Ok(MySqlColumn {
        name,
        type_info,
        ordinal,
        flags: Some(def.flags),
        origin,
    })
}

