fn add_old_children(&self, path: Vec<usize>, positions: &mut OldChildren) {
    match self {
        LNode::Fragment(frag) => {
            for (idx, child) in frag.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        LNode::Element { children, .. } => {
            for (idx, child) in children.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        // need to insert dynamic content and children, as these might change
        LNode::DynChild(_) => {
            positions.0.insert(self.clone(), path);
        }
        LNode::Component { children, .. } => {
            positions.0.insert(self.clone(), path.clone());

            for (idx, child) in children.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        // can just create text nodes, whatever
        LNode::Text(_) => {}
    }
}

pub async fn init_verification(
    flow_id: String,
) -> Result<Option<ViewableVerificationFlow>, ServerFnError> {
    let cookie_jar = leptos_axum::extract::<axum_extra::extract::CookieJar>().await?;
    let csrf_cookie = cookie_jar
        .iter()
        .filter(|cookie| cookie.name().contains("csrf_token"))
        .next()
        .ok_or(ServerFnError::new(
            "Expecting a csrf_token cookie to already be set if fetching a pre-existing flow",
        ))?;
    let client = reqwest::ClientBuilder::new()
        .redirect(reqwest::redirect::Policy::none())
        .build()?;
    // https://www.ory.sh/docs/reference/api#tag/frontend/operation/getVerificationFlow
    let resp = client
        .get("http://127.0.0.1:4433/self-service/verification/flows")
        .query(&[("id", flow_id)])
        //.header("x-csrf-token", csrf_token)
        //.header("content-type","application/json")
        .header(
            "cookie",
            format!("{}={}", csrf_cookie.name(), csrf_cookie.value()),
        )
        .send()
        .await?;
    if resp.status().as_u16() == 403 {
        debug!("{:#?}", resp.text().await?);
        Ok(None)
    } else {
        let flow = resp.json::<ViewableVerificationFlow>().await?;
        Ok(Some(flow))
    }
}

fn parse(input: ParseStream) -> Result<Self> {
    let input = syn::DeriveInput::parse(input)?;

    let ty = match input.data {
        syn::Data::Struct(s) => {
            let fields = match s.fields {
                syn::Fields::Unit => {
                    abort!(s.semi_token, "unit structs are not supported");
                }
                syn::Fields::Named(fields) => {
                    fields.named.into_iter().collect::<Vec<_>>()
                }
                syn::Fields::Unnamed(fields) => {
                    fields.unnamed.into_iter().collect::<Vec<_>>()
                }
            };

            ModelTy::Struct { fields }
        }
        syn::Data::Enum(e) => ModelTy::Enum {
            variants: e.variants.into_iter().collect(),
        },
        _ => {
            abort_call_site!(
                "only structs and enums can be used with `Store`"
            );
        }
    };

    Ok(Self {
        vis: input.vis,
        generics: input.generics,
        name: input.ident,
        ty,
    })
}

fn insert_node(
    parent: &Self::Element,
    new_child: &Self::Node,
    anchor: Option<&Self::Node>,
) {
    debug_assert!(&parent.0 != new_child);
    // remove if already mounted
    if let Some(parent) = MockDom::get_parent(new_child) {
        let parent = Element(parent);
        MockDom::remove_node(&parent, new_child);
    }
    // mount on new parent
    Document::with_node_mut(parent.0 .0, |parent| {
        if let NodeType::Element {
            ref mut children, ..
        } = parent.ty
        {
            match anchor {
                None => children.push(new_child.clone()),
                Some(anchor) => {
                    let anchor_pos = children
                        .iter()
                        .position(|item| item.0 == anchor.0)
                        .expect("anchor is not a child of the parent");
                    children.insert(anchor_pos, new_child.clone());
                }
            }
        } else {
            panic!("parent is not an element");
        }
    });
    // set parent on child node
    Document::with_node_mut(new_child.0, |node| {
        node.parent = Some(parent.0 .0)
    });
}

async fn main() -> anyhow::Result<()> {
    if let Err(err) = env::var("RUST_LOG") {
        match err {
            env::VarError::NotPresent => {
                env::set_var("RUST_LOG", "debug");
            }
            env::VarError::NotUnicode(_) => {
                return Err(anyhow::anyhow!(
                    "The value of 'RUST_LOG' does not contain valid unicode \
                     data."
                ));
            }
        }
    }
    env_logger::init();

    let shared_state = Arc::new(RwLock::new(AppState::default()));

    let cors_layer = CorsLayer::new()
        .allow_methods([Method::GET, Method::POST])
        .allow_origin(Any);

    let app = Router::new()
        .route("/login", post(login))
        .route("/logout", post(logout))
        .route("/users", post(create_user))
        .route("/users", get(get_user_info))
        .route_layer(cors_layer)
        .with_state(shared_state);

    let addr = "0.0.0.0:3000".parse::<SocketAddr>()?;
    log::info!("Start listening on http://{addr}");
    let listener = TcpListener::bind(addr).await?;
    axum::serve(listener, app.into_make_service()).await?;
    Ok(())
}

pub fn get_related_entity_modules(&self) -> Vec<Ident> {
    // 1st step get conjunct relations data
    let conjunct_related_attrs = self
        .conjunct_relations
        .iter()
        .map(|conj| conj.get_to_snake_case());

    // helper function that generates attributes for `Relation` data
    let produce_relation_attrs = |rel: &Relation, _reverse: bool| match rel.get_module_name() {
        Some(module_name) => module_name,
        None => format_ident!("self"),
    };

    // 2nd step get reverse self relations data
    let self_relations_reverse_attrs = self
        .relations
        .iter()
        .filter(|rel| rel.self_referencing)
        .map(|rel| produce_relation_attrs(rel, true));

    // 3rd step get normal relations data
    self.relations
        .iter()
        .map(|rel| produce_relation_attrs(rel, false))
        .chain(self_relations_reverse_attrs)
        .chain(conjunct_related_attrs)
        .collect()
}

pub fn gen_expanded_model_struct(
    entity: &Entity,
    with_serde: &WithSerde,
    column_option: &ColumnOption,
    serde_skip_deserializing_primary_key: bool,
    serde_skip_hidden_column: bool,
    model_extra_derives: &TokenStream,
    model_extra_attributes: &TokenStream,
) -> TokenStream {
    let column_names_snake_case = entity.get_column_names_snake_case();
    let column_rs_types = entity.get_column_rs_types(column_option);
    let if_eq_needed = entity.get_eq_needed();
    let serde_attributes = entity.get_column_serde_attributes(
        serde_skip_deserializing_primary_key,
        serde_skip_hidden_column,
    );
    let extra_derive = with_serde.extra_derive();

    quote! {
        #[derive(Clone, Debug, PartialEq, DeriveModel, DeriveActiveModel #if_eq_needed #extra_derive #model_extra_derives)]
        #model_extra_attributes
        pub struct Model {
            #(
                #serde_attributes
                pub #column_names_snake_case: #column_rs_types,
            )*
        }
    }
}

async fn fetch_raw() -> Result<(), DbErr> {
    let (db, pages) = setup();

    let mut paginator = fruit::Entity::find()
        .from_raw_sql(RAW_STMT.clone())
        .paginate(&db, 2);

    assert_eq!(paginator.fetch().await?, pages[0].clone());
    paginator.next();

    assert_eq!(paginator.fetch().await?, pages[1].clone());
    paginator.next();

    assert_eq!(paginator.fetch().await?, pages[2].clone());

    let mut select = SelectStatement::new()
        .exprs([
            Expr::col((fruit::Entity, fruit::Column::Id)),
            Expr::col((fruit::Entity, fruit::Column::Name)),
            Expr::col((fruit::Entity, fruit::Column::CakeId)),
        ])
        .from(fruit::Entity)
        .to_owned();

    let query_builder = db.get_database_backend();
    let stmts = [
        query_builder.build(select.clone().offset(0).limit(2)),
        query_builder.build(select.clone().offset(2).limit(2)),
        query_builder.build(select.offset(4).limit(2)),
    ];

    assert_eq!(db.into_transaction_log(), Transaction::wrap(stmts));
    Ok(())
}

async fn start() -> std::io::Result<()> {
    unsafe {
        std::env::set_var("RUST_LOG", "debug");
    }
    tracing_subscriber::fmt::init();

    // get env vars
    dotenvy::dotenv().ok();
    let db_url = env::var("DATABASE_URL").expect("DATABASE_URL is not set in .env file");
    let host = env::var("HOST").expect("HOST is not set in .env file");
    let port = env::var("PORT").expect("PORT is not set in .env file");
    let server_url = format!("{host}:{port}");

    // create post table if not exists
    let conn = Database::connect(&db_url).await.unwrap();
    Migrator::up(&conn, None).await.unwrap();
    let templates = Tera::new(concat!(env!("CARGO_MANIFEST_DIR"), "/templates/**/*")).unwrap();
    let state = AppState { templates, conn };

    println!("Starting server at {server_url}");

    let app = Route::new()
        .at("/", post(create).get(list))
        .at("/new", new)
        .at("/:id", get(edit).post(update))
        .at("/delete/:id", post(delete))
        .nest(
            "/static",
            StaticFilesEndpoint::new(concat!(env!("CARGO_MANIFEST_DIR"), "/static")),
        )
        .data(state);
    let server = Server::new(TcpListener::bind(format!("{host}:{port}")));
    server.run(app).await
}
